/-- Bounded outcome `|Y| ≤ M` almost surely under `P`. -/
def BoundedOutcome {d : ℕ} (P : DoseLaw d) (M : ℝ) : Prop :=
  ∀ᵐ O ∂P.dataMeasure, |O.Y| ≤ M

